<div class="page-head"><div><h2>Performance</h2><p class="muted">Performance review, approval workflow, score report, and bonus input basis.</p></div></div>
<div class="grid grid-2"><div class="card"><h3>Create Review</h3><form method="post" action="<?=url('/performance/store')?>"><?=csrf_field()?><div class="form-row"><div><label>Employee</label><select name="employee_id"><?php foreach($employees as $e): ?><option value="<?=e($e['id'])?>"><?=e($e['full_name'])?></option><?php endforeach; ?></select></div><div><label>Period</label><input name="period_name" placeholder="2026 Q1" required></div><div><label>Score</label><input name="score" type="number" step="0.01"></div><div><label>Status</label><select name="status"><option>draft</option><option>manager_review</option><option>approved</option></select></div></div><br><button class="btn btn-primary">Save Review</button></form></div><div class="card"><h3>Report</h3><div class="grid grid-3"><div><div class="muted">Reviews</div><div class="stat"><?=count($rows)?></div></div><div><div class="muted">Approved</div><div class="stat"><?=count(array_filter($rows,fn($r)=>$r['status']==='approved'))?></div></div><div><div class="muted">Avg Score</div><div class="stat"><?=count($rows)?number_format(array_sum(array_map(fn($r)=>(float)$r['score'],$rows))/count($rows),1):'0'?></div></div></div></div></div><br>
<div class="card"><h3>List Data & Approval</h3><table class="table"><tr><th>Employee</th><th>Period</th><th>Score</th><th>Status</th><th>Action</th></tr><?php foreach($rows as $r): ?><tr><td><?=e($r['employee_name'])?></td><td><?=e($r['period_name'])?></td><td><?=e($r['score'])?></td><td><span class="badge badge-info"><?=e($r['status'])?></span></td><td><form method="post" action="<?=url('/performance/workflow')?>" style="display:flex;gap:6px"><?=csrf_field()?><input type="hidden" name="id" value="<?=e($r['id'])?>"><input name="score" type="number" step="0.01" value="<?=e($r['score'])?>"><select name="status"><option>draft</option><option>manager_review</option><option>approved</option><option>rejected</option></select><button class="btn btn-light">Update</button></form></td></tr><?php endforeach; ?></table></div>
